__kernel void benchmark_func(const class_T seed, __global class_T* g_data) {
  const size_t lid = get_local_id(0);
  const size_t gid = get_global_id(0);
  const size_t group = get_group_id(0);

#ifdef BLOCK_STRIDED
  const size_t stride = (size_t)blockdim;
  const size_t idx = group * ((size_t)blockdim * (size_t)ELEMENTS_PER_THREAD) + lid;
#else
  const size_t stride = get_global_size(0);
  const size_t idx = gid;
#endif

  const size_t big_stride = get_global_size(0) * (size_t)ELEMENTS_PER_THREAD;

  class_T tmps[ELEMENTS_PER_THREAD];

  for (uint k = 0; k < (uint)FUSION_DEGREE; ++k) {
    for (uint j = 0; j < (uint)ELEMENTS_PER_THREAD; ++j) {
      tmps[j] = g_data[idx + (size_t)j * stride + (size_t)k * big_stride];
      for (int i = 0; i < COMPUTE_ITERATIONS; ++i) {
        tmps[j] = mad_t(tmps[j], tmps[j], seed);
      }
    }

    class_T sum = conv_int_t(0, seed);
    for (uint j = 0; j + 1 < (uint)ELEMENTS_PER_THREAD; j += 2) {
      sum = mad_t(tmps[j], tmps[j + 1], sum);
    }
    if ((ELEMENTS_PER_THREAD & 1) != 0) {
      sum = mad_t(tmps[ELEMENTS_PER_THREAD - 1], conv_int_t(1, seed), sum);
    }

    if (equal_t(sum, conv_int_t(-1, seed))) {
      g_data[idx + (size_t)k * big_stride] = sum;
    }
  }
}

